using FluentValidation;

namespace EventForge.Server.Validators.Teams;

/// <summary>
/// FluentValidation validator for UpdateMembershipCardDto.
/// Auto-generated by scripts/FluentValidationGenerator; TODO-REVIEW comments require manual follow-up.
/// </summary>
public class UpdateMembershipCardDtoValidator : AbstractValidator<Prym.DTOs.Teams.UpdateMembershipCardDto>
{
    public UpdateMembershipCardDtoValidator()
    {
        RuleFor(x => x.CardNumber)
            .MaximumLength(50)
            .WithMessage("Il campo CardNumber non può superare 50 caratteri.");

        RuleFor(x => x.Federation)
            .MaximumLength(100)
            .WithMessage("Il campo Federation non può superare 100 caratteri.");

        RuleFor(x => x.Category)
            .MaximumLength(50)
            .WithMessage("Il campo Category non può superare 50 caratteri.");

        RuleFor(x => x.Notes)
            .MaximumLength(500)
            .WithMessage("Il campo Notes non può superare 500 caratteri.");
    }
}
